// Get data from all inputs
const webhookData = $('Webhook Trigger').first().json.body;
const frameworkTaxonomy = $('Fetch Framework Taxonomy').first().json;
const personalityCalibration = $('Fetch Personality Calibration').first().json;
const questionBank = $('Fetch Question Bank').first().json;

return [{
  json: {
    user_input: {
      task_description: webhookData.task_description || '',
      personality_type: webhookData.personality_type || null,
      trait_percentages: webhookData.trait_percentages || null
    },
    reference_docs: {
      framework_taxonomy: frameworkTaxonomy.content || '',
      personality_calibration: personalityCalibration.content || '',
      question_bank: questionBank.content || ''
    },
    has_personality_data: !!webhookData.personality_type
  }
}];

