const input = $('Prepare Input').first().json;
const claudeResponse = $input.first().json;

// Parse the Claude response - it might be in message.content or directly in the response
let analysisData;
try {
  const content = claudeResponse.message?.content || claudeResponse.text || claudeResponse;
  if (typeof content === 'string') {
    // Remove any markdown code blocks if present
    const cleanedContent = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    analysisData = JSON.parse(cleanedContent);
  } else {
    analysisData = content;
  }
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + e.message);
}

return [{
  json: {
    success: true,
    data: analysisData,
    original_input: {
      task_description: input.user_input.task_description,
      personality_type: input.user_input.personality_type,
      trait_percentages: input.user_input.trait_percentages
    },
    error: null
  }
}];

const errorInfo = $input.first().json;

return [{
  json: {
    success: false,
    data: null,
    error: {
      message: 'An error occurred during analysis',
      details: errorInfo.message || errorInfo.error || 'Unknown error'
    }
  }
}];
